		'image' => 'guide-custom-shipping', 
		'steps' => array(
			array('title' => 'Open Custom & Shipping dashboard', 'body' => 'In client CP go to ERP Suite → Custom & Shipping (sidebar group) or Shop → Finance → ERP with area custom_shipping. The dashboard shows total, draft, submitted, and cleared counts plus six category cards.'),
			array('title' => 'Review declaration categories', 'body' => 'Import (12 types), Export (13), Transit (6), Temporary Admission (3), Transfer (2), and LGP warehouse intake each have their own card with live counts. Click a card to list declarations in that category.'),
			array('title' => 'Start from quick action or type list', 'body' => 'Use quick actions for Import to Local from ROW, Export from Local to ROW, FZ transit in, or New LGP entry — or open a category and pick any of the 36 registered declaration types from the Excel workbook.'),
			array('title' => 'Fill core required fields', 'body' => 'Every customs declaration requires Company, Customs emirate (Dubai, Sharjah, Abu Dhabi, etc.), Declaration type, Date, and Declaration date. Add B/L #, SRV #, supplier detail, currency, and invoice amount from your customs paperwork.'),
			array('title' => 'Import workflow fields', 'body' => 'Import declarations add supplier code (customs), custom inspection flag, and D365 PO reference — matching the Excel import columns for local, FZ, CW, and courier entries.'),
			array('title' => 'Multiple HS code line items', 'body' => 'Use the declaration line items grid to add one row per HS code: country of origin, quantity, unit (PCS, KG, etc.), volume (CBM), amount, and optional weight. Totals sum qty, volume, and amount; lists show item count per declaration.'),
			array('title' => 'Export, transit & transfer fields', 'body' => 'Export, transit, temporary admission, and transfer types capture import (re-export) declaration ref #, document expiry date, D365 SO reference, customer ref, and customer country where applicable on re-export and return flows.'),
			array('title' => 'LGP warehouse intake', 'body' => 'LGP entries use a dedicated form: customer ref, cargo source, goods coming from, warehouse name/number, local company, purpose of entry, packing list, and commercial invoice are required. Use line items for multiple HS codes, weights, volumes, and values.'),
			array('title' => 'Save draft and submit', 'body' => 'Click Save draft while paperwork is in progress. Open the saved record from the category list, review captured fields, then Submit when filed with UAE customs. Status flows draft → submitted → cleared.'),
			array('title' => 'Run declaration reports', 'body' => 'Open Reports from the Custom & Shipping dashboard. Use Declaration search to filter by date, type, category, company, emirate, and status — or search by declaration #, supplier, and SRV/shipment no. Export CSV or print results.'),
			array('title' => 'Cost summary and duty stub', 'body' => 'Cost summary aggregates invoice amount, total cost, and line-item amounts by company and category. Duty report lists HS codes and origins per line with declaration totals — full duty calculation arrives in a later phase.'),
			array('title' => 'Re-export and document expiry', 'body' => 'Re-export tracking shows import-for-re-export and re-export declarations with links to the original import ref #. Document expiry lists overdue and upcoming expiry dates within a configurable day window.'),
